+
+            //Add new submarker
+            void addSubFractalMarker(FractalMarker submarker);
+
+            //Find inner corners
+            std::vector<cv::Point3f> findInnerCorners();
+
+            //Marker MAT
+            const cv::Mat mat() const
+            {
+                return _M;
+            }
+
+            //Marker mask (mask applied to submarkers)
+            const cv::Mat mask() const
+            {
+                return _mask;
+            }
+
+            //Total number of bits
+            int nBits()
+            {
+                return _M.total();
+            }
+
+            //Submarkers ids
