+    S01 = ATA02 * ATA21;
+    S02 = -ATA02 * ATA11;
+    S10 = ATA12 * ATA20;
+    S11 = ATA00 * ATA22 - ATA02 * ATA20;
+    S12 = -ATA00 * ATA12;
+    S20 = -ATA11 * ATA20;
+    S21 = -ATA00 * ATA21;
