+int MarkerDetector_Impl::perimeter(const vector<Point2f>& a)
+{
+    int sum = 0;
+    for (unsigned int i = 0; i < a.size(); i++)
+    {
+        int i2 = (i + 1) % a.size();
+        sum += static_cast<int>( sqrt((a[i].x - a[i2].x) * (a[i].x - a[i2].x) +
+                                      (a[i].y - a[i2].y) * (a[i].y - a[i2].y)));
+    }
+    return sum;
+}
